        function getTableIndexFromId(id) {
            if (!id) return null;
            const prefix = id.charAt(0);
            switch(prefix) {
                case 'B':
                case 'C':
                case 'G':
                    return '0'; // Characters
                case 'I':
                    return '1'; // Inventory
                case 'E':
                    return '9'; // Equipment
                case 'T':
                    return '6'; // Tasks
                case 'S':
                    return '8'; // Skills
                case 'W': // World Events
                    return '5';
                case 'P': // Spirit Beasts
                    return '7';
                default:
                    return null;
            }
        }

