let minY = points[0][1], maxY = points[0][1];

for (let i = 1; i < points.length; i++) {
minX = Math.min(minX, points[i][0]);
maxX = Math.max(maxX, points[i][0]);
minY = Math.min(minY, points[i][1]);
maxY = Math.max(maxY, points[i][1]);
