        async function handleRandomizeTraits() {
            const cost = 10;
            if (calculateRemainingPoints() < cost) {
                await showCustomAlert('属性点不足，无法刷新词条！');
                return;
            }

            creationState.totalPoints -= cost;

            const container = document.getElementById('trait-options-container');
