                    keywordInput.type = 'text';
                    keywordInput.placeholder = '关键词';
                    keywordInput.value = requirement.keyword || '';
                    container.appendChild(keywordInput);
                    break;
                case 'variable':
                    const tableSelect = document.createElement('select');
                    tableSelect.innerHTML = `
