                    const colInput = document.createElement('input');
                    colInput.type = 'number';
                    colInput.placeholder = '列号';
                    colInput.min = 0;
                    colInput.value = requirement.col || '';

                    const varValueInput = document.createElement('input');
                    varValueInput.type = 'text';
                    varValueInput.placeholder = '包含的值';
                    varValueInput.value = requirement.value || '';

                    container.append(tableSelect, idInput, colInput, varValueInput);
